ol.li:
Here is an example NAD to create a Layer 2 VLAN
                    sub-interface:apiVersion: "k8s.cni.cncf.io/v1"
kind: NetworkAttachmentDefinition
metadata:
  name: vswitch-bd201-sub      
spec:
  config: '{
    "cniVersion":"0.4.0",
    "name": "vswitch-bd201-sub",
    "capabilities":{"ips":true},
    "plugins": [
      {
        "type": "jcnr",
        "args": {
          "instanceName": "vswitch",               
          "instanceType": "virtual-switch",        
          "bridgeDomain": "bd201",                
          "bridgeVlanId": "201",                  
          "parentInterface": "net1",                
          "interface": "net1.201"                 
        },
        "ipam": {
          "type": "static",
          "capabilities":{"ips":true},
          "addresses":[
            {
              "address":"10.3.0.1/24",
              "gateway":"10.3.0.254"
            },
            {
              "address":"2001:db8:3003::10.3.0.1/120",
              "gateway":"2001:db8:3003::10.3.0.1"
            }
          ]
        },
        "kubeConfig":"/etc/kubernetes/kubelet.conf"
      }
    ]
  }'The
                    NAD defines a bridge domain bd201 and a sub-interface
                        net1.201 with a parent interface net1. The
                    pod will be attached in the virtual-switch instance.. It also
                    defines a static IP address to be assigned to the pod interface.
